    static ListNode merge(ListNode a,ListNode b){ListNode d=new ListNode(0),c=d;while(a!=null&&b!=null){if(a.val<=b.val){c.next=a;a=a.next;}else{c.next=b;b=b.next;}c=c.next;}c.next=a!=null?a:b;return d.next;}
    static boolean isSorted(ListNode h){while(h!=null&&h.next!=null){if(h.val>h.next.val)return false;h=h.next;}return true;}
